properties.definition:
${(() => {// Write the body of your
// function here.

// Remember to return a value. 

const finalFromJson = {}

const type = queueType?.value
const visibilityTimeout = visibilityTimeoutForQueue?.value ? visibilityTimeoutForQueue?.value : Number(30)
const receiveMessageWaittime =  receiveMessgeWaitTimeForQueue?.value ? receiveMessgeWaitTimeForQueue?.value : Number(0)
const delaySeconds =  deliveryDelayForQueue?.value ? deliveryDelayForQueue?.value : Number(0)
const messageRetentionPeriod = messageRetentionPeriodForQueue?.value ? messageRetentionPeriodForQueue?.value : "345600"
const maxMessageSize = maxMessageSizeForQueue?.value ? (Number(maxMessageSizeForQueue?.value) * 1024) : (Number(256)*1024)
const serveSideEncryption = serverSideEncryptionForQueue?.value
const encryptionKeyType = encryptionKeyTypeForQueue?.value
const accessPolicy = accessPolicyForQueue?.value
const kmsDataKeyReusePeriod =  kmsDataKeyReusePeriodSecondsForQueue?.value ? kmsDataKeyReusePeriodSecondsForQueue?.value : Number(300)
const kmsMasterKeyID = kmsMasterKeyIdForQueue?.value
const redriveAllowPolicy = redriveAllowPolicyToggleForQueue?.value
const redrivePermission = redrivePermissionSelectorForQueue?.value
const sourceArns = sourceQueueArnsForQueue?.value
const selectedDLQ = chooseDLQ?.value
const maxReceives = maximumReceivesForDLQ?.value
const contentBasedDupliction =  fifoCheckbox?.isChecked[0]
const highThroughPutQueue = fifoCheckbox?.isChecked[1]

const duplicationScope  = duplicationScopeForQueue?.value
const fifoThroughputLimit = fifoThroughputLimitForQueue?.value


finalFromJson.DelaySeconds = delaySeconds
finalFromJson.ReceiveMessageWaitTimeSeconds = receiveMessageWaittime
finalFromJson.VisibilityTimeout = visibilityTimeout
finalFromJson.MaximumMessageSize = maxMessageSize.toString()
finalFromJson.MessageRetentionPeriod =  messageRetentionPeriod
finalFromJson.Policy = JSON.stringify(accessPolicy)


if(type === "FIFO"){
    finalFromJson.FifoQueue = "true"

    if(contentBasedDupliction){
        finalFromJson.ContentBasedDeduplication = "true"
    }

    if(highThroughPutQueue){
        finalFromJson.DeduplicationScope = "messageGroup"
        finalFromJson.FifoThroughputLimit = "perMessageGroupId"
    }
    else{
        finalFromJson.DeduplicationScope = duplicationScope
        finalFromJson.FifoThroughputLimit = fifoThroughputLimit
    }

}


if(serveSideEncryption === "Enabled"){
    if(encryptionKeyType === "AWS Key Management Service key (SSE-KMS)"){
        finalFromJson.KmsMasterKeyId = kmsMasterKeyID
        finalFromJson.KmsDataKeyReusePeriodSeconds = kmsDataKeyReusePeriod
    }
    else{
        finalFromJson.SqsManagedSseEnabled = "true"
    }

}

if(redriveAllowPolicy === "Enabled"){

    const redriveAllowPolicydata = {}
    redriveAllowPolicydata.redrivePermission = redrivePermission

    if(redrivePermission === "byQueue"){
        redriveAllowPolicydata.sourceQueueArns = sourceArns
    }
    finalFromJson.RedriveAllowPolicy = JSON.stringify(redriveAllowPolicydata)
}

if(setDLQBoolean?.value === "Enabled"){

    const redrivePolicyData = {
        deadLetterTargetArn : selectedDLQ,
        maxReceiveCount : maxReceives
    }
    finalFromJson.RedrivePolicy = JSON.stringify(redrivePolicyData)
}
return finalFromJson;})}

