provider "aws" {
  region = "${createSQSRegion.value}"
}

resource "aws_sqs_queue" "my_queue" {
  name                       = "${queueType.value === "FIFO" ? queueDetailsName.value.endsWith(".fifo") ? queueDetailsName.value : queueDetailsName.value.concat(".fifo") : queueDetailsName.value}"
  visibility_timeout_seconds = ${Number(visibilityTimeoutForQueue.value)}
  delay_seconds              = ${Number(deliveryDelayForQueue?.value)}
  message_retention_seconds  = ${Number(messageRetentionPeriodForQueue.value)}   
  max_message_size           = ${Number(maxMessageSizeForQueue?.value) * 1024}
  receive_wait_time_seconds  = ${Number(receiveMessgeWaitTimeForQueue.value)}
  fifo_queue                 = ${queueType.value === "FIFO" ? true : false }
}

